def solve(capacity: int, ops: list[str]) -> list[int]:
    cache = OrderedDict()
    res = []
    for op in ops:
        parts = op.split()
        if parts[0] == "put":
            if capacity == 0:
                continue
            k, v = int(parts[1]), int(parts[2])
            if k in cache:
                cache.move_to_end(k)
            cache[k] = v
            if len(cache) > capacity:
                cache.popitem(last=False)
        else:
            k = int(parts[1])
            if k in cache:
                cache.move_to_end(k)
                res.append(cache[k])
            else:
                res.append(-1)
    return res
