def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    rev_deps = {}
    for pkg, dependencies in deps.items():
        for dep in dependencies:
            if dep not in rev_deps:
                rev_deps[dep] = set()
            rev_deps[dep].add(pkg)

    affected = set(changed)
    queue = deque(changed)

    while queue:
        curr = queue.popleft()
        if curr in rev_deps:
            for dependent in rev_deps[curr]:
                if dependent not in affected:
                    affected.add(dependent)
                    queue.append(dependent)

    return sorted(list(affected))
